  Value *A, *B;
  // PtrToInts are NonEqual if their Ptrs are NonEqual.
  // Check PtrToInt type matches the pointer size.
  if (match(V1, m_PtrToIntSameSize(Q.DL, m_Value(A))) &&
      match(V2, m_PtrToIntSameSize(Q.DL, m_Value(B))))
    return isKnownNonEqual(A, B, DemandedElts, Q, Depth + 1);

  // If V1 and V2 are pointers, check if there's an assumption that implies
  // ptrtoint(V1) - ptrtoint(V2) != 0. This would imply V1 != V2.
  if (V1->getType()->isPointerTy() && V2->getType()->isPointerTy()) {
    // Create the expression ptrtoint(V1) - ptrtoint(V2)
    Type *IntPtrTy = Q.DL.getIntPtrType(V1->getType());
    Value *V1Int = Builder.CreatePtrToInt(V1, IntPtrTy);
    Value *V2Int = Builder.CreatePtrToInt(V2, IntPtrTy);
    Value *Diff = Builder.CreateSub(V1Int, V2Int);

    // Check if Diff is known to be non-zero
    if (isKnownNonZero(Diff, Q, Depth + 1))
      return true;
  }

  if (isKnownNonEqualFromContext(V1, V2, Q, Depth))
    return true;

  return false;
}
