{"command": "cd /app/data/auto-opt/utils/llvm-118106 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Analysis/ValueTracking.cpp 3879 3902
  if (!Q.AC)
    return false;

  // Try to infer NonEqual based on information from assumptions.
  for (auto &AssumeVH : Q.AC->assumptionsFor(V1)) {
    if (!AssumeVH)
      continue;
    CallInst *I = cast<CallInst>(AssumeVH);

    assert(I->getFunction() == Q.CxtI->getFunction() &&
           "Got assumption for the wrong function!");
    assert(I->getIntrinsicID() == Intrinsic::assume &&
           "must be an assume intrinsic");

    if (isImpliedCondition(I->getArgOperand(0), ICmpInst::ICMP_NE, V1, V2, Q.DL,
                           /*LHSIsTrue=*/true, Depth)
            .value_or(false) &&
        isValidAssumeForContext(I, Q.CxtI, Q.DT))
      return true;
  }

  // If V1 and V2 are pointers, check if there's an assumption that implies
  // ptrtoint(V1) - ptrtoint(V2) != 0.
  if (V1->getType()->isPointerTy() && V2->getType()->isPointerTy()) {
    // Iterate over all assumptions to find one that implies
    // sub(ptrtoint(V1), ptrtoint(V2)) != 0
    for (auto &AssumeVH : Q.AC->assumptions()) {
      if (!AssumeVH.Assume)
        continue;
      CallInst *I = cast<CallInst>(AssumeVH.Assume);

      assert(I->getFunction() == Q.CxtI->getFunction() &&
             "Got assumption for the wrong function!");
      assert(I->getIntrinsicID() == Intrinsic::assume &&
             "must be an assume intrinsic");

      // Check if the assumption implies sub(ptrtoint(V1), ptrtoint(V2)) != 0
      // We do this by checking if the assumption implies that the difference
      // is non-zero.
      Value *Diff;
      if (match(I->getArgOperand(0),
                m_c_ICmp(ICmpInst::ICMP_EQ,
                         m_Sub(m_PtrToInt(m_Specific(V1)),
                               m_PtrToInt(m_Specific(V2))),
                         m_Value(Diff))) ||
          match(I->getArgOperand(0),
                m_c_ICmp(ICmpInst::ICMP_EQ,
                         m_Sub(m_PtrToInt(m_Specific(V2)),
                               m_PtrToInt(m_Specific(V1))),
                         m_Value(Diff)))) {
        // If Diff is known to be non-zero, then the difference is non-zero,
        // which implies V1 != V2.
        if (isKnownNonZero(Diff, Q, Depth + 1) &&
            isValidAssumeForContext(I, Q.CxtI, Q.DT))
          return true;
      }
    }
  }

  return false;
}
